-- Rebuild asset-level area_breakdown rows from checked DB_일반 Excel values.
-- Scope: ll_lease_attributes rows where attribute_type='area_breakdown' for matching Excel assets only.

with expected_assets as (
  select 'A120085001'::text as asset_code
  union all
  select 'A112527001'::text as asset_code
  union all
  select 'A112755001'::text as asset_code
  union all
  select 'A112527002'::text as asset_code
  union all
  select 'A112299001'::text as asset_code
  union all
  select 'A112505001'::text as asset_code
  union all
  select 'A112127001'::text as asset_code
  union all
  select 'AP00014001'::text as asset_code
  union all
  select 'A112500003'::text as asset_code
  union all
  select 'S00002001'::text as asset_code
  union all
  select 'A112527003'::text as asset_code
  union all
  select 'A112606001'::text as asset_code
  union all
  select 'A112573001'::text as asset_code
  union all
  select 'A112721001'::text as asset_code
  union all
  select 'A112500002'::text as asset_code
  union all
  select 'A112642001'::text as asset_code
), matched_assets as (
  select a.asset_id
  from expected_assets e
  join public.ll_assets a on a.asset_code = e.asset_code
)
delete from public.ll_lease_attributes
where attribute_type = 'area_breakdown'
  and asset_id in (select asset_id from matched_assets);

