), representative_spaces as (
  select distinct on (a.asset_code)
    a.asset_code, s.lease_space_id, s.lease_id, s.asset_id, s.tenant_id
  from public.ll_assets a
  join public.ll_lease_spaces s on s.asset_id = a.asset_id
  where a.asset_code in (select asset_code from area_rows)
    and coalesce(lower(trim(s.contract_status::text)), '') not in ('inactive','n','no','false','0','vacant','vacancy','empty','placeholder')
  order by a.asset_code, s.lease_space_id
)
insert into public.ll_lease_attributes (
  attribute_type, lease_space_id, lease_id, asset_id, tenant_id,
  attribute_key, attribute_label, value_numeric, value_sqm, value_py, unit_label,
  basis, source_table, source_legacy_id, source_payload, review_status, review_note, updated_at
)
select
  'area_breakdown', rs.lease_space_id, rs.lease_id, rs.asset_id, rs.tenant_id,
  ar.attribute_key, ar.attribute_label, ar.value_sqm, ar.value_sqm, ar.value_sqm * 0.3025, '㎡',
  'DB_일반', 'xlsx:DB_일반:asset_area_breakdown:20260612', ar.source_legacy_id, ar.source_payload,
  'source_excel_asset_rebuilt', 'DB_일반 원본 엑셀 기준 자산 단위 면적 구성 재적재', now()
from area_rows ar
join representative_spaces rs on rs.asset_code = ar.asset_code
on conflict (source_table, source_legacy_id) do update set
  lease_space_id = excluded.lease_space_id,
  lease_id = excluded.lease_id,
  asset_id = excluded.asset_id,
  tenant_id = excluded.tenant_id,
  attribute_label = excluded.attribute_label,
  value_numeric = excluded.value_numeric,
  value_sqm = excluded.value_sqm,
  value_py = excluded.value_py,
  source_payload = excluded.source_payload,
  review_status = excluded.review_status,
  review_note = excluded.review_note,
  updated_at = now();
